const SERVICES = [
    ["01", "AI Consulting 1-1", "90-min private strategy session. Walk away with a custom roadmap and your top 3 automation wins."],
    ["02", "Custom AI Websites", "Next.js sites engineered to convert — shipped in under 10 days. SEO-ready from day one."],
    ["03", "Custom Dashboards", "Live revenue intelligence — KPI tracking, lead scoring, CRM sync, forecasting. All in one view."],
    ["04", "PDF to Video", "Transform complex documents into narrated videos in 25+ languages. Instantly."],
    ["05", "Photo & Video Ads", "AI-generated product ads — print, social, video — at 10× the speed and 1/5 the cost."],
];

function Globe() {
    return (
        <div style={{ position: "relative", width: 340, height: 340, flexShrink: 0 }}>
            {/* Halo glow */}
            <div style={{ position: "absolute", inset: -40, borderRadius: "50%", background: "radial-gradient(circle, rgba(6,182,212,0.1) 0%, transparent 70%)", filter: "blur(20px)", pointerEvents: "none" }} />
            {/* Outer orbit */}
            <div className="animate-slow-spin" style={{ position: "absolute", inset: 0, borderRadius: "50%", border: "1px solid rgba(6,182,212,0.2)" }} />
            {/* Inner orbit */}
            <div style={{ position: "absolute", inset: 18, borderRadius: "50%", border: "1px solid rgba(139,92,246,0.15)", animation: "slow-spin 55s linear infinite reverse" }} />
            {/* Globe sphere */}
            <div style={{ position: "absolute", inset: 40, borderRadius: "50%", background: "radial-gradient(circle at 38% 32%, #0f2e3a 0%, #04090d 70%)", border: "1px solid rgba(6,182,212,0.3)", boxShadow: "0 0 60px rgba(6,182,212,0.12), inset 0 0 60px rgba(0,0,0,0.9)", overflow: "hidden" }}>
                <svg viewBox="0 0 200 200" style={{ position: "absolute", inset: 0, width: "100%", height: "100%", opacity: 0.55 }}>
                    {/* North America */}
                    <ellipse cx="58" cy="65" rx="26" ry="17" fill="#06b6d4" opacity="0.7" transform="rotate(-18 58 65)" />
                    {/* Europe/Asia */}
                    <ellipse cx="140" cy="72" rx="17" ry="30" fill="#06b6d4" opacity="0.6" transform="rotate(22 140 72)" />
                    {/* South America */}
                    <ellipse cx="72" cy="138" rx="14" ry="20" fill="#06b6d4" opacity="0.55" transform="rotate(8 72 138)" />
                    {/* Africa */}
                    <ellipse cx="110" cy="130" rx="16" ry="22" fill="#06b6d4" opacity="0.5" transform="rotate(-5 110 130)" />
                    {/* Australia */}
                    <ellipse cx="155" cy="145" rx="12" ry="8" fill="#06b6d4" opacity="0.5" transform="rotate(-10 155 145)" />
                    {/* Grid lines */}
                    {[50, 75, 100, 125, 150].map(y => (
                        <line key={y} x1="0" x2="200" y1={y} y2={y} stroke="rgba(6,182,212,0.1)" strokeWidth="0.6" />
                    ))}
                    {[50, 100, 150].map(x => (
                        <line key={x} x1={x} x2={x} y1="0" y2="200" stroke="rgba(6,182,212,0.1)" strokeWidth="0.6" />
                    ))}
                </svg>
                {/* Specular highlight */}
                <div style={{ position: "absolute", inset: 0, background: "radial-gradient(circle at 38% 32%, rgba(6,182,212,0.22) 0%, transparent 55%)" }} />
            </div>
            {/* Pulsing data points */}
            {[
                { top: "24%", left: "33%", size: 12, color: "#06b6d4", delay: "0s" },
                { top: "64%", left: "26%", size: 8, color: "#06b6d4", delay: "0.7s" },
                { top: "50%", left: "66%", size: 10, color: "#06b6d4", delay: "1.3s" },
                { top: "30%", left: "66%", size: 7, color: "#8b5cf6", delay: "1.9s" },
                { top: "70%", left: "60%", size: 6, color: "#10b981", delay: "0.4s" },
            ].map((d, i) => (
                <div key={i} className="animate-pulse-slow" style={{ position: "absolute", top: d.top, left: d.left, width: d.size, height: d.size, borderRadius: "50%", background: d.color, boxShadow: `0 0 ${d.size * 2}px ${d.color}`, animationDelay: d.delay }} />
            ))}
        </div>
    );
}

export default function HeroSection() {
    return (
        <section className="star-bg relative min-h-screen flex flex-col justify-center pt-24 pb-20 px-6 overflow-hidden">
            {/* Ambient blobs */}
            <div style={{ position: "absolute", top: "20%", left: "10%", width: 500, height: 500, borderRadius: "50%", background: "radial-gradient(circle, rgba(6,182,212,0.06) 0%, transparent 70%)", filter: "blur(60px)", pointerEvents: "none" }} />
            <div style={{ position: "absolute", top: "40%", right: "5%", width: 400, height: 400, borderRadius: "50%", background: "radial-gradient(circle, rgba(139,92,246,0.05) 0%, transparent 70%)", filter: "blur(60px)", pointerEvents: "none" }} />

            <div className="max-w-6xl mx-auto w-full relative z-10">
                {/* Top badge */}
                <div className="flex justify-start mb-8">
                    <div className="badge-live">AI Strategy Group — Accepting clients</div>
                </div>

                {/* Two-column: copy + globe */}
                <div className="flex flex-col lg:flex-row items-start lg:items-center gap-12 lg:gap-20">

                    {/* Left: Headline */}
                    <div className="flex-1 min-w-0">
                        <h1 className="text-5xl sm:text-6xl lg:text-7xl font-black tracking-[-0.05em] text-white leading-[1.0] mb-6">
                            BOWEN AI<br />
                            <span style={{ background: "linear-gradient(135deg, #06b6d4, #8b5cf6)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text" }}>
                                STRATEGY
                            </span>
                            <br />GROUP
                        </h1>

                        <p className="text-xl text-zinc-400 leading-relaxed mb-10 max-w-lg">
                            Custom AI websites, dashboards, ads, and strategy — built for founders who want results in days, not months.
                        </p>

                        {/* Service pills */}
                        <div className="flex flex-wrap gap-2 mb-10">
                            {["1-1 Consulting", "AI Websites", "Dashboards", "PDF to Video", "Photo & Video Ads"].map((s) => (
                                <span key={s} className="text-sm font-medium px-3 py-1.5 rounded-full"
                                    style={{ background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.1)", color: "#a1a1aa" }}>
                                    {s}
                                </span>
                            ))}
                        </div>

                        <div className="flex flex-col sm:flex-row gap-3">
                            <a href="#consulting"><button className="btn-primary text-[15px]">Book a Free Strategy Call →</button></a>
                            <a href="#showcase"><button className="btn-ghost text-[15px]">See Our Work</button></a>
                        </div>
                    </div>

                    {/* Right: Globe */}
                    <div className="flex flex-col items-center gap-6 lg:shrink-0">
                        <Globe />
                        <div className="flex items-center gap-6 text-sm text-zinc-600">
                            <span>500+ projects</span>
                            <span style={{ color: "rgba(255,255,255,0.1)" }}>|</span>
                            <span>48h delivery</span>
                            <span style={{ color: "rgba(255,255,255,0.1)" }}>|</span>
                            <span>Global clients</span>
                        </div>
                    </div>
                </div>

                {/* Service list — below the hero split */}
                <div className="mt-20 pt-16" style={{ borderTop: "1px solid rgba(255,255,255,0.06)" }}>
                    <p className="section-label">What we build</p>
                    <div className="grid sm:grid-cols-2 lg:grid-cols-5 gap-4">
                        {SERVICES.map(([num, title, desc]) => (
                            <div key={num} className="group p-5 rounded-2xl transition-all cursor-default"
                                style={{ background: "rgba(255,255,255,0.02)", border: "1px solid rgba(255,255,255,0.06)" }}
                                onMouseEnter={(e) => (e.currentTarget.style.borderColor = "rgba(255,255,255,0.14)")}
                                onMouseLeave={(e) => (e.currentTarget.style.borderColor = "rgba(255,255,255,0.06)")}
                            >
                                <div className="mono text-xs font-bold mb-3" style={{ color: "#06b6d4" }}>{num}</div>
                                <div className="text-base font-semibold text-white mb-2">{title}</div>
                                <div className="text-sm leading-relaxed" style={{ color: "#52525b" }}>{desc}</div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </section>
    );
}
